export function getCaliforniaHormoneClinicsByCity(citySlug: string): HormoneClinic[] {
  return californiaHormoneClinics.filter(c => c.citySlug === citySlug);
}

export function getCaliforniaHormoneCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of californiaHormoneClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
